{
  "summary": "This paper proposes language-based methods to approximate human similarity judgments across images, audio, and video modalities, leveraging textual descriptions and large language model embeddings to reduce the need for exhaustive pairwise human annotations. It introduces the STEP-Tag adaptive crowdsourcing pipeline for collecting high-quality semantic tags and demonstrates that combining language embeddings with sensory DNN embeddings yields superior similarity approximations approaching inter-rater reliability.",
  "strengths": [
    {
      "point": "Comprehensive large-scale evaluation across multiple modalities and models",
      "evidence": "Evaluated over 600 pre-trained models spanning images, audio, and video, including 9 multimodal CLIP models, providing broad insights into similarity approximation performance."
    },
    {
      "point": "Novel and efficient language-based similarity approximation methods",
      "evidence": "Proposed O(N) human judgment methods using textual descriptions and LLM embeddings that outperform DNN-only approaches and are modality-agnostic."
    },
    {
      "point": "Introduction of the STEP-Tag adaptive crowdsourcing pipeline",
      "evidence": "Developed and validated a novel iterative tagging pipeline that improves tag quality and diversity without requiring a predefined taxonomy."
    },
    {
      "point": "Stacked embedding approach combining language and sensory models",
      "evidence": "Demonstrated that concatenating LLM and DNN embeddings with rescaling yields the best approximation of human similarity, approaching inter-rater reliability."
    },
    {
      "point": "Release of extensive behavioral datasets and code",
      "evidence": "Provided a large dataset with over 200,000 human judgments and all code for replication, facilitating future research."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior language-based similarity work",
      "evidence": "The paper lacks discussion or comparison to existing methods leveraging language or textual metadata for similarity estimation, weakening novelty claims."
    },
    {
      "point": "Lack of ablation studies on STEP-Tag pipeline components",
      "evidence": "No analysis isolating the impact of rating, flagging, or iterative tag addition on tag quality and diversity."
    },
    {
      "point": "Unclear justification and tuning of rescaling hyperparameter in stacked methods",
      "evidence": "No explanation of how the rescaling parameter is chosen or its sensitivity, raising reproducibility concerns."
    },
    {
      "point": "Potentially unfair baseline comparisons due to differing human judgment budgets",
      "evidence": "Language-based methods require O(N) human judgments while DNN methods require O(1), but this discrepancy is not controlled or discussed."
    },
    {
      "point": "Evaluation relies solely on Pearson correlation metric",
      "evidence": "No use of additional metrics like Spearman correlation or retrieval-based measures to capture nonlinear or rank-based similarity."
    },
    {
      "point": "Limited analysis and reporting of inter-rater reliability (IRR)",
      "evidence": "Details on IRR computation, variability, and strictness as an upper bound are missing."
    },
    {
      "point": "Reproducibility hindered by missing details on crowdsourcing protocols and LLM embedding extraction",
      "evidence": "No description of participant instructions, quality control, demographics, or specifics of LLM models and embedding procedures."
    },
    {
      "point": "Ambiguous definition of similarity across modalities",
      "evidence": "No clear criteria or instructions ensuring consistent similarity judgments across images, audio, and video."
    },
    {
      "point": "Insufficient explanation of Word Frequency Analysis methods",
      "evidence": "Unclear how co-occurrence counts, Rouge, BM25, and TF-IDF are combined or adapted for similarity approximation."
    },
    {
      "point": "No discussion of language biases or cultural variability",
      "evidence": "Potential biases in language-based similarity approximations and their impact on generalizability are not addressed."
    },
    {
      "point": "Scalability of STEP-Tag pipeline not quantitatively analyzed",
      "evidence": "No cost, time, or participant requirement analysis as dataset size increases."
    },
    {
      "point": "Limited dataset diversity and unclear generalizability",
      "evidence": "Experiments cover few datasets/domains and do not evaluate performance on low-resource languages or domains without LLMs."
    },
    {
      "point": "No analysis of noise or variability in textual descriptions",
      "evidence": "Effects of ambiguity or inconsistency in captions or tags on similarity approximation are not studied."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed LLM-based similarity method compare quantitatively and qualitatively to prior language-based similarity approaches?",
      "motivation": "Clarifying this would strengthen claims of novelty and contextualize contributions within existing literature."
    },
    {
      "question": "What is the sensitivity of the stacked embedding approach to the rescaling hyperparameter, and how robust are results to its tuning?",
      "motivation": "Understanding this is critical for reproducibility and practical application of the hybrid method."
    },
    {
      "question": "How do differences in human judgment budgets (O(N) vs. O(1)) affect the fairness of method comparisons, and can evaluations be adjusted to control for this?",
      "motivation": "Ensuring fair comparisons is essential to accurately assess the benefits of language-based methods."
    },
    {
      "question": "Can the STEP-Tag pipeline scale efficiently to very large datasets, and what are the associated costs and time requirements?",
      "motivation": "Quantifying scalability is important for practical adoption in large-scale similarity data collection."
    },
    {
      "question": "How do language biases and cultural variability in textual descriptions impact the generalizability and fairness of similarity approximations?",
      "motivation": "Addressing this is necessary for deploying these methods across diverse populations and languages."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
